"use client";

import React, { useState } from "react";
import {
  CopilotChat,
  useFrontendTool,
  useConfigureSuggestions,
} from "@copilotkit/react-core/v2";
import { CopilotKit } from "@copilotkit/react-core";
import { z } from "zod";
import { ApprovalDialog, PendingApproval } from "./approval-dialog";

// Mock tickets the "operator" is working through. Hard-coded so the
// agent has real-looking data to reference when asked to take an action.
const SUPPORT_TICKETS = [
  {
    id: "#12345",
    customer: "Jordan Rivera",
    subject: "Refund request — duplicate charge",
    status: "Open",
    amount: 50,
  },
  {
    id: "#12346",
    customer: "Priya Shah",
    subject: "Downgrade plan to Starter",
    status: "Open",
    amount: 0,
  },
  {
    id: "#12347",
    customer: "Morgan Lee",
    subject: "Escalate: payment stuck in pending",
    status: "Escalating",
    amount: 0,
  },
];

export default function HitlInAppDemo() {
  return (
    <CopilotKit runtimeUrl="/api/copilotkit" agent="hitl-in-app">
      <Layout />
    </CopilotKit>
  );
}

// Internal state shape: the args the agent passed plus the `resolve`
// fn we captured from the Promise returned by the tool handler.
type ResolveFn = (value: { approved: boolean; reason?: string }) => void;
type DialogState =
  | { open: false }
  | { open: true; pending: PendingApproval; resolve: ResolveFn };

function Layout() {
  const [dialog, setDialog] = useState<DialogState>({ open: false });

  useConfigureSuggestions({
    suggestions: [
      {
        title: "Approve refund for #12345",
        message:
          "Please approve a $50 refund to Jordan Rivera on ticket #12345 for the duplicate charge.",
      },
      {
        title: "Downgrade plan for #12346",
        message:
          "Please downgrade Priya Shah (#12346) to the Starter plan effective next billing cycle.",
      },
      {
        title: "Escalate ticket #12347",
        message:
          "Please escalate ticket #12347 to the payments team — Morgan Lee's payment is stuck.",
      },
    ],
    available: "always",
  });

  useFrontendTool({
    name: "request_user_approval",
    description:
      "Ask the operator to approve or reject an action before you take it. " +
      "The operator will respond via an in-app modal dialog that appears " +
      "OUTSIDE the chat surface. The tool returns an object of the shape " +
      "{ approved: boolean, reason?: string }.",
    parameters: z.object({
      message: z
        .string()
        .describe(
          "Short summary of the action needing approval (include concrete numbers / IDs).",
        ),
      context: z
        .string()
        .optional()
        .describe(
          "Optional extra context — e.g. the ticket ID or policy rule.",
        ),
    }),
    handler: async ({
      message,
      context,
    }: {
      message: string;
      context?: string;
    }) => {
      // Return a Promise whose `resolve` we stash into state. The modal
      // dialog calls `resolve(...)` when the user clicks Approve / Reject,
      // which completes THIS handler and hands the value back to the
      // agent as the tool result.
      return await new Promise<{ approved: boolean; reason?: string }>(
        (resolve) => {
          setDialog({ open: true, pending: { message, context }, resolve });
        },
      );
    },
  });

  const handleResolve = (result: { approved: boolean; reason?: string }) => {
    if (dialog.open) {
      dialog.resolve(result);
      setDialog({ open: false });
    }
  };

  return (
    <div className="grid h-screen grid-cols-[1fr_420px] bg-gray-50">
      <TicketsPanel />
      <div className="border-l border-gray-200 bg-white">
        <CopilotChat agentId="hitl-in-app" className="h-full" />
      </div>
      {dialog.open && (
        <ApprovalDialog pending={dialog.pending} onResolve={handleResolve} />
      )}
    </div>
  );
}

function TicketsPanel() {
  return (
    <div className="flex h-full flex-col overflow-hidden">
      <header className="border-b border-gray-200 bg-white px-6 py-4">
        <div className="text-xs font-medium uppercase tracking-wide text-gray-500">
          Support Inbox
        </div>
        <h1 className="text-xl font-semibold text-gray-900">Open tickets</h1>
        <p className="mt-1 text-sm text-gray-600">
          Ask the copilot to take an action. Every customer-affecting action
          will pop up an approval dialog here in the app — outside the chat.
        </p>
      </header>
      <div className="flex-1 overflow-y-auto p-6">
        <ul className="space-y-3">
          {SUPPORT_TICKETS.map((t) => (
            <li
              key={t.id}
              data-testid={`ticket-${t.id.replace("#", "")}`}
              className="rounded-lg border border-gray-200 bg-white p-4 shadow-sm"
            >
              <div className="flex items-center justify-between">
                <span className="font-mono text-xs text-gray-500">{t.id}</span>
                <span
                  className={
                    t.status === "Escalating"
                      ? "rounded-full bg-amber-100 px-2 py-0.5 text-xs font-medium text-amber-800"
                      : "rounded-full bg-green-100 px-2 py-0.5 text-xs font-medium text-green-800"
                  }
                >
                  {t.status}
                </span>
              </div>
              <div className="mt-2 text-sm font-semibold text-gray-900">
                {t.customer}
              </div>
              <div className="text-sm text-gray-700">{t.subject}</div>
              {t.amount > 0 && (
                <div className="mt-2 text-xs text-gray-500">
                  Disputed amount: ${t.amount.toFixed(2)}
                </div>
              )}
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
}

import { NextRequest, NextResponse } from "next/server";
import {
  CopilotRuntime,
  ExperimentalEmptyAdapter,
  copilotRuntimeNextJSAppRouterEndpoint,
} from "@copilotkit/runtime";
import { LangGraphAgent } from "@copilotkit/runtime/langgraph";

const LANGGRAPH_URL =
  process.env.LANGGRAPH_DEPLOYMENT_URL || "http://localhost:8123";

console.log("[copilotkit/route] Initializing CopilotKit runtime");
console.log(`[copilotkit/route] LANGGRAPH_URL: ${LANGGRAPH_URL}`);
console.log(
  `[copilotkit/route] LANGSMITH_API_KEY: ${process.env.LANGSMITH_API_KEY ? "set" : "not set"}`,
);

function createAgent(graphId: string = "sample_agent") {
  return new LangGraphAgent({
    deploymentUrl: LANGGRAPH_URL,
    graphId,
    langsmithApiKey: process.env.LANGSMITH_API_KEY || "",
  });
}

// Cells that share the neutral default "helpful, concise assistant" graph.
// These cells are chrome / UI / docs demos — the agent has no specialized
// behavior. Each still gets its own registered name so per-cell frontend
// tool/component registrations scope correctly.
const neutralAssistantCells = [
  "human_in_the_loop",
  "shared-state-read",
  "shared-state-write",
  "prebuilt-sidebar",
  "prebuilt-popup",
  "chat-slots",
  "chat-customization-css",
  "headless-simple",
  // NOTE: `beautiful-chat` is NOT in this list — it has its own dedicated
  // runtime at /api/copilotkit-beautiful-chat (needed for openGenerativeUI +
  // a2ui + mcpApps combined-runtime shape). See the beautiful-chat page.tsx.
];

const agents: Record<string, LangGraphAgent> = {};
for (const name of neutralAssistantCells) {
  agents[name] = createAgent();
}

// Dedicated-graph agents.
agents["tool-rendering"] = createAgent("tool_rendering");
agents["tool-rendering-default-catchall"] = createAgent("tool_rendering");
agents["tool-rendering-custom-catchall"] = createAgent("tool_rendering");
agents["tool-rendering-reasoning-chain"] = createAgent(
  "tool_rendering_reasoning_chain",
);
// Declarative Generative UI (A2UI — Dynamic Schema) demo uses its own graph.
agents["declarative-gen-ui"] = createAgent("a2ui_dynamic");
// Declarative Generative UI (A2UI — Fixed Schema) demo.
agents["a2ui-fixed-schema"] = createAgent("a2ui_fixed");
// Dedicated graphs for stub cells (ported from 4084).
agents["shared-state-streaming"] = createAgent("shared_state_streaming");
agents["subagents"] = createAgent("subagents");
// Basic cells with their own dedicated graphs (neutral assistant variants
// split out of main.py so main.py stays a pure default).
agents["agentic_chat"] = createAgent("agentic_chat");
agents["frontend_tools"] = createAgent("frontend_tools");
// Frontend Tools (Async) — dedicated cell demonstrating an async useFrontendTool
// handler (simulated client-side notes DB query). Backend has no tools; the
// frontend registers `query_notes` via useFrontendTool and the agent awaits
// its returned result.
agents["frontend-tools-async"] = createAgent("frontend_tools_async");
agents["gen-ui-agent"] = createAgent("gen_ui_agent");
// Tool-Based Generative UI — chart-viz system prompt lives in its own graph.
agents["gen-ui-tool-based"] = createAgent("gen_ui_tool_based");
// Reasoning variants.
agents["agentic-chat-reasoning"] = createAgent("reasoning_agent");
agents["reasoning-default-render"] = createAgent("reasoning_agent");
// Interrupt variants.
agents["gen-ui-interrupt"] = createAgent("interrupt_agent");
agents["interrupt-headless"] = createAgent("interrupt_agent");
// HITL dedicated (tools=[] + tailored system prompt).
agents["hitl-in-chat"] = createAgent("hitl_in_chat");
// In-App HITL — async frontend-tool + app-level modal (outside chat).
agents["hitl-in-app"] = createAgent("hitl_in_app");
// Shared state R+W and read-only agent context.
agents["shared-state-read-write"] = createAgent("shared_state_read_write");
agents["readonly-state-agent-context"] = createAgent(
  "readonly_state_agent_context",
);

// Also register a default
agents["default"] = createAgent();

console.log(
  `[copilotkit/route] Registered ${Object.keys(agents).length} agent names: ${Object.keys(agents).join(", ")}`,
);

export const POST = async (req: NextRequest) => {
  const url = req.url;
  const contentType = req.headers.get("content-type");
  console.log(`[copilotkit/route] POST ${url} (content-type: ${contentType})`);

  try {
    const { handleRequest } = copilotRuntimeNextJSAppRouterEndpoint({
      endpoint: "/api/copilotkit",
      serviceAdapter: new ExperimentalEmptyAdapter(),
      runtime: new CopilotRuntime({
        // @ts-ignore -- Published CopilotRuntime agents type wraps Record in MaybePromise<NonEmptyRecord<...>> which rejects plain Records; fixed in source, pending release
        agents,
        // NOTE: A2UI is intentionally NOT enabled here. The A2UI cells
        // (declarative-gen-ui and a2ui-fixed-schema) each live on their own
        // dedicated runtime endpoint (/api/copilotkit-declarative-gen-ui and
        // /api/copilotkit-a2ui-fixed-schema respectively), mirroring the
        // beautiful-chat topology. Each of those runtimes configures
        // `a2ui.injectA2UITool: false` because the backend graphs own their
        // own A2UI-rendering tools explicitly (matching the canonical
        // reference at examples/integrations/langgraph-python).
        // OpenGenerativeUI lives in /api/copilotkit-ogui for the same reason.
        // MCP Apps is in /api/copilotkit-mcp-apps.
      }),
    });

    const response = await handleRequest(req);
    console.log(`[copilotkit/route] Response status: ${response.status}`);
    return response;
  } catch (error: any) {
    console.error(`[copilotkit/route] ERROR: ${error.message}`);
    console.error(`[copilotkit/route] Stack: ${error.stack}`);
    return NextResponse.json(
      { error: error.message, stack: error.stack },
      { status: 500 },
    );
  }
};

export const GET = async () => {
  console.log("[copilotkit/route] GET /api/copilotkit (health probe)");

  let langGraphStatus = "unknown";
  try {
    const res = await fetch(`${LANGGRAPH_URL}/ok`, {
      signal: AbortSignal.timeout(3000),
    });
    langGraphStatus = res.ok ? "reachable" : `error (${res.status})`;
  } catch (e: any) {
    langGraphStatus = `unreachable (${e.message})`;
  }

  return NextResponse.json({
    status: "ok",
    langgraph_url: LANGGRAPH_URL,
    langgraph_status: langGraphStatus,
    env: {
      OPENAI_API_KEY: process.env.OPENAI_API_KEY ? "set" : "NOT SET",
      LANGSMITH_API_KEY: process.env.LANGSMITH_API_KEY ? "set" : "NOT SET",
      NODE_ENV: process.env.NODE_ENV,
    },
  });
};

"use client";

// Modal dialog rendered at the APP level (portal'd to <body>) — not
// inside the chat bubble tree. The caller supplies `pending` (the
// message/context the agent wants approval for) and an `onResolve`
// completion callback. The user's click on Approve / Reject fires the
// callback, which resolves the pending frontend-tool Promise back in
// the parent page.

import React, { useEffect, useState } from "react";
import { createPortal } from "react-dom";

export type PendingApproval = {
  message: string;
  context?: string;
};

type Props = {
  pending: PendingApproval;
  onResolve: (result: { approved: boolean; reason?: string }) => void;
};

export function ApprovalDialog({ pending, onResolve }: Props) {
  const [reason, setReason] = useState("");
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  if (!mounted) return null;

  const content = (
    <div
      data-testid="approval-dialog-overlay"
      className="fixed inset-0 z-50 flex items-center justify-center bg-[#010507]/40 backdrop-blur-sm"
    >
      <div
        data-testid="approval-dialog"
        role="dialog"
        aria-modal="true"
        className="w-full max-w-md rounded-2xl border border-[#DBDBE5] bg-white p-6 shadow-sm"
      >
        <div className="mb-2 text-[10px] font-medium uppercase tracking-[0.14em] text-[#57575B]">
          Action requires your approval
        </div>
        <h2 className="mb-3 text-lg font-semibold text-[#010507]">
          {pending.message}
        </h2>
        {pending.context && (
          <p className="mb-4 rounded-xl border border-[#E9E9EF] bg-[#FAFAFC] p-3 text-sm text-[#57575B]">
            {pending.context}
          </p>
        )}
        <label className="mb-1 block text-xs font-medium text-[#57575B]">
          Note (optional)
        </label>
        <textarea
          data-testid="approval-dialog-reason"
          value={reason}
          onChange={(e) => setReason(e.target.value)}
          placeholder="Add a short note the assistant will see…"
          className="mb-4 w-full resize-none rounded-xl border border-[#DBDBE5] px-3 py-2 text-sm text-[#010507] focus:border-[#BEC2FF] focus:outline-none focus:ring-2 focus:ring-[#BEC2FF33]"
          rows={2}
        />
        <div className="flex items-center justify-end gap-2">
          <button
            type="button"
            data-testid="approval-dialog-reject"
            onClick={() =>
              onResolve({
                approved: false,
                reason: reason.trim() || undefined,
              })
            }
            className="rounded-xl border border-[#DBDBE5] bg-white px-4 py-2 text-sm font-medium text-[#57575B] hover:bg-[#FAFAFC] transition-colors"
          >
            Reject
          </button>
          <button
            type="button"
            data-testid="approval-dialog-approve"
            onClick={() =>
              onResolve({
                approved: true,
                reason: reason.trim() || undefined,
              })
            }
            className="rounded-xl bg-[#010507] px-4 py-2 text-sm font-medium text-white hover:bg-[#2B2B2B] transition-colors"
          >
            Approve
          </button>
        </div>
      </div>
    </div>
  );

  return createPortal(content, document.body);
}

