"use client";

// Tool Rendering — PRIMARY (per-tool + catch-all) variant.
//
// The most sophisticated point in the three-way progression: the same
// backend tools as the `tool-rendering-default-catchall` and
// `tool-rendering-custom-catchall` cells are now surfaced via
// dedicated, branded UI for the two "interesting" tools, with a
// catch-all covering everything else:
//
//   get_weather     → <WeatherCard />       (per-tool renderer)
//   search_flights  → <FlightListCard />    (per-tool renderer)
//   *               → <CustomCatchallRenderer /> (wildcard fallback)

import React from "react";
import {
  CopilotKit,
  CopilotChat,
  useRenderTool,
  useDefaultRenderTool,
  useConfigureSuggestions,
} from "@copilotkit/react-core/v2";
import { z } from "zod";
import { WeatherCard } from "./weather-card";
import { FlightListCard, type Flight } from "./flight-list-card";
import {
  CustomCatchallRenderer,
  type CatchallToolStatus,
} from "./custom-catchall-renderer";

interface WeatherResult {
  city?: string;
  temperature?: number;
  humidity?: number;
  wind_speed?: number;
  conditions?: string;
}

interface FlightSearchResult {
  origin?: string;
  destination?: string;
  flights?: Flight[];
}

function parseJsonResult<T>(result: unknown): T {
  if (!result) return {} as T;
  try {
    return (typeof result === "string" ? JSON.parse(result) : result) as T;
  } catch {
    return {} as T;
  }
}

export default function ToolRenderingDemo() {
  return (
    <CopilotKit runtimeUrl="/api/copilotkit" agent="tool-rendering">
      <div className="flex justify-center items-center h-screen w-full">
        <div className="h-full w-full max-w-4xl">
          <Chat />
        </div>
      </div>
    </CopilotKit>
  );
}

function Chat() {
  // Per-tool renderer #1: get_weather → branded WeatherCard.
  useRenderTool(
    {
      name: "get_weather",
      parameters: z.object({
        location: z.string(),
      }),
      render: ({ parameters, result, status }) => {
        const loading = status !== "complete";
        const parsed = parseJsonResult<WeatherResult>(result);
        return (
          <WeatherCard
            loading={loading}
            location={parameters?.location ?? parsed.city ?? ""}
            temperature={parsed.temperature}
            humidity={parsed.humidity}
            windSpeed={parsed.wind_speed}
            conditions={parsed.conditions}
          />
        );
      },
    },
    [],
  );

  // Per-tool renderer #2: search_flights → branded FlightListCard.
  useRenderTool(
    {
      name: "search_flights",
      parameters: z.object({
        origin: z.string(),
        destination: z.string(),
      }),
      render: ({ parameters, result, status }) => {
        const loading = status !== "complete";
        const parsed = parseJsonResult<FlightSearchResult>(result);
        return (
          <FlightListCard
            loading={loading}
            origin={parameters?.origin ?? parsed.origin ?? ""}
            destination={parameters?.destination ?? parsed.destination ?? ""}
            flights={parsed.flights ?? []}
          />
        );
      },
    },
    [],
  );

  // Wildcard catch-all for every remaining tool (get_stock_price,
  // roll_dice, anything the agent might add later).
  useDefaultRenderTool(
    {
      render: ({ name, parameters, status, result }) => (
        <CustomCatchallRenderer
          name={name}
          parameters={parameters}
          status={status as CatchallToolStatus}
          result={result}
        />
      ),
    },
    [],
  );

  useConfigureSuggestions({
    suggestions: [
      {
        title: "Weather in SF",
        message: "What's the weather in San Francisco?",
      },
      {
        title: "Find flights",
        message: "Find flights from SFO to JFK.",
      },
      {
        title: "Stock price",
        message: "What's the current price of AAPL?",
      },
      {
        title: "Roll a d20",
        message: "Roll a 20-sided die.",
      },
    ],
    available: "always",
  });

  return (
    <CopilotChat agentId="tool-rendering" className="h-full rounded-2xl" />
  );
}

import { NextRequest, NextResponse } from "next/server";
import {
  CopilotRuntime,
  ExperimentalEmptyAdapter,
  copilotRuntimeNextJSAppRouterEndpoint,
} from "@copilotkit/runtime";
import { LangGraphAgent } from "@copilotkit/runtime/langgraph";

const LANGGRAPH_URL =
  process.env.LANGGRAPH_DEPLOYMENT_URL || "http://localhost:8123";

console.log("[copilotkit/route] Initializing CopilotKit runtime");
console.log(`[copilotkit/route] LANGGRAPH_URL: ${LANGGRAPH_URL}`);
console.log(
  `[copilotkit/route] LANGSMITH_API_KEY: ${process.env.LANGSMITH_API_KEY ? "set" : "not set"}`,
);

function createAgent(graphId: string = "sample_agent") {
  return new LangGraphAgent({
    deploymentUrl: LANGGRAPH_URL,
    graphId,
    langsmithApiKey: process.env.LANGSMITH_API_KEY || "",
  });
}

// Cells that share the neutral default "helpful, concise assistant" graph.
// These cells are chrome / UI / docs demos — the agent has no specialized
// behavior. Each still gets its own registered name so per-cell frontend
// tool/component registrations scope correctly.
const neutralAssistantCells = [
  "human_in_the_loop",
  "shared-state-read",
  "shared-state-write",
  "prebuilt-sidebar",
  "prebuilt-popup",
  "chat-slots",
  "chat-customization-css",
  "headless-simple",
  // NOTE: `beautiful-chat` is NOT in this list — it has its own dedicated
  // runtime at /api/copilotkit-beautiful-chat (needed for openGenerativeUI +
  // a2ui + mcpApps combined-runtime shape). See the beautiful-chat page.tsx.
];

const agents: Record<string, LangGraphAgent> = {};
for (const name of neutralAssistantCells) {
  agents[name] = createAgent();
}

// Dedicated-graph agents.
agents["tool-rendering"] = createAgent("tool_rendering");
agents["tool-rendering-default-catchall"] = createAgent("tool_rendering");
agents["tool-rendering-custom-catchall"] = createAgent("tool_rendering");
agents["tool-rendering-reasoning-chain"] = createAgent(
  "tool_rendering_reasoning_chain",
);
// Declarative Generative UI (A2UI — Dynamic Schema) demo uses its own graph.
agents["declarative-gen-ui"] = createAgent("a2ui_dynamic");
// Declarative Generative UI (A2UI — Fixed Schema) demo.
agents["a2ui-fixed-schema"] = createAgent("a2ui_fixed");
// Dedicated graphs for stub cells (ported from 4084).
agents["shared-state-streaming"] = createAgent("shared_state_streaming");
agents["subagents"] = createAgent("subagents");
// Basic cells with their own dedicated graphs (neutral assistant variants
// split out of main.py so main.py stays a pure default).
agents["agentic_chat"] = createAgent("agentic_chat");
agents["frontend_tools"] = createAgent("frontend_tools");
// Frontend Tools (Async) — dedicated cell demonstrating an async useFrontendTool
// handler (simulated client-side notes DB query). Backend has no tools; the
// frontend registers `query_notes` via useFrontendTool and the agent awaits
// its returned result.
agents["frontend-tools-async"] = createAgent("frontend_tools_async");
agents["gen-ui-agent"] = createAgent("gen_ui_agent");
// Tool-Based Generative UI — chart-viz system prompt lives in its own graph.
agents["gen-ui-tool-based"] = createAgent("gen_ui_tool_based");
// Reasoning variants.
agents["agentic-chat-reasoning"] = createAgent("reasoning_agent");
agents["reasoning-default-render"] = createAgent("reasoning_agent");
// Interrupt variants.
agents["gen-ui-interrupt"] = createAgent("interrupt_agent");
agents["interrupt-headless"] = createAgent("interrupt_agent");
// HITL dedicated (tools=[] + tailored system prompt).
agents["hitl-in-chat"] = createAgent("hitl_in_chat");
// In-App HITL — async frontend-tool + app-level modal (outside chat).
agents["hitl-in-app"] = createAgent("hitl_in_app");
// Shared state R+W and read-only agent context.
agents["shared-state-read-write"] = createAgent("shared_state_read_write");
agents["readonly-state-agent-context"] = createAgent(
  "readonly_state_agent_context",
);

// Also register a default
agents["default"] = createAgent();

console.log(
  `[copilotkit/route] Registered ${Object.keys(agents).length} agent names: ${Object.keys(agents).join(", ")}`,
);

export const POST = async (req: NextRequest) => {
  const url = req.url;
  const contentType = req.headers.get("content-type");
  console.log(`[copilotkit/route] POST ${url} (content-type: ${contentType})`);

  try {
    const { handleRequest } = copilotRuntimeNextJSAppRouterEndpoint({
      endpoint: "/api/copilotkit",
      serviceAdapter: new ExperimentalEmptyAdapter(),
      runtime: new CopilotRuntime({
        // @ts-ignore -- Published CopilotRuntime agents type wraps Record in MaybePromise<NonEmptyRecord<...>> which rejects plain Records; fixed in source, pending release
        agents,
        // NOTE: A2UI is intentionally NOT enabled here. The A2UI cells
        // (declarative-gen-ui and a2ui-fixed-schema) each live on their own
        // dedicated runtime endpoint (/api/copilotkit-declarative-gen-ui and
        // /api/copilotkit-a2ui-fixed-schema respectively), mirroring the
        // beautiful-chat topology. Each of those runtimes configures
        // `a2ui.injectA2UITool: false` because the backend graphs own their
        // own A2UI-rendering tools explicitly (matching the canonical
        // reference at examples/integrations/langgraph-python).
        // OpenGenerativeUI lives in /api/copilotkit-ogui for the same reason.
        // MCP Apps is in /api/copilotkit-mcp-apps.
      }),
    });

    const response = await handleRequest(req);
    console.log(`[copilotkit/route] Response status: ${response.status}`);
    return response;
  } catch (error: any) {
    console.error(`[copilotkit/route] ERROR: ${error.message}`);
    console.error(`[copilotkit/route] Stack: ${error.stack}`);
    return NextResponse.json(
      { error: error.message, stack: error.stack },
      { status: 500 },
    );
  }
};

export const GET = async () => {
  console.log("[copilotkit/route] GET /api/copilotkit (health probe)");

  let langGraphStatus = "unknown";
  try {
    const res = await fetch(`${LANGGRAPH_URL}/ok`, {
      signal: AbortSignal.timeout(3000),
    });
    langGraphStatus = res.ok ? "reachable" : `error (${res.status})`;
  } catch (e: any) {
    langGraphStatus = `unreachable (${e.message})`;
  }

  return NextResponse.json({
    status: "ok",
    langgraph_url: LANGGRAPH_URL,
    langgraph_status: langGraphStatus,
    env: {
      OPENAI_API_KEY: process.env.OPENAI_API_KEY ? "set" : "NOT SET",
      LANGSMITH_API_KEY: process.env.LANGSMITH_API_KEY ? "set" : "NOT SET",
      NODE_ENV: process.env.NODE_ENV,
    },
  });
};

"use client";

import React from "react";

// Branded catch-all renderer for tools that don't have a dedicated
// per-tool renderer. Registered via `useDefaultRenderTool` in page.tsx,
// this component handles every tool call NOT claimed by a named
// `useRenderTool` registration (e.g. get_stock_price, roll_dice).
//
// Shows the tool name, a status badge, pretty-printed arguments, and
// the result (as JSON). Each cell is self-contained, so this file is
// intentionally duplicated from the `tool-rendering-custom-catchall`
// cell rather than imported across cell boundaries.

export type CatchallToolStatus = "inProgress" | "executing" | "complete";

export interface CustomCatchallRendererProps {
  name: string;
  status: CatchallToolStatus;
  parameters: unknown;
  result: string | undefined;
}

export function CustomCatchallRenderer({
  name,
  status,
  parameters,
  result,
}: CustomCatchallRendererProps) {
  const parsedResult = parseResult(result);
  const done = status === "complete";

  return (
    <div
      data-testid="custom-catchall-card"
      data-tool-name={name}
      data-status={status}
      className="my-3 overflow-hidden rounded-2xl border border-[#DBDBE5] bg-white shadow-sm"
    >
      <div className="flex items-center justify-between border-b border-[#E9E9EF] bg-[#FAFAFC] px-4 py-2.5">
        <div className="flex items-center gap-2">
          <span className="text-[10px] uppercase tracking-[0.14em] text-[#838389]">
            Tool
          </span>
          <span
            data-testid="custom-catchall-tool-name"
            className="font-mono text-sm text-[#010507]"
          >
            {name}
          </span>
        </div>
        <StatusBadge status={status} />
      </div>

      <div className="grid gap-3 p-4 text-sm">
        <Section label="Arguments">
          <pre
            data-testid="custom-catchall-args"
            className="overflow-x-auto rounded-lg border border-[#E9E9EF] bg-[#FAFAFC] p-2.5 font-mono text-xs text-[#010507]"
          >
            {safeStringify(parameters)}
          </pre>
        </Section>

        <Section label="Result">
          {done ? (
            <pre
              data-testid="custom-catchall-result"
              className="overflow-x-auto rounded-lg border border-[#85ECCE4D] bg-[#85ECCE]/10 p-2.5 font-mono text-xs text-[#010507]"
            >
              {parsedResult !== undefined
                ? safeStringify(parsedResult)
                : "(empty)"}
            </pre>
          ) : (
            <p className="text-xs italic text-[#838389]">
              waiting for tool to finish…
            </p>
          )}
        </Section>
      </div>
    </div>
  );
}

function Section({
  label,
  children,
}: {
  label: string;
  children: React.ReactNode;
}) {
  return (
    <div>
      <div className="mb-1.5 text-[10px] font-medium uppercase tracking-[0.14em] text-[#838389]">
        {label}
      </div>
      {children}
    </div>
  );
}

function StatusBadge({ status }: { status: CatchallToolStatus }) {
  const { label, tone } = describeStatus(status);
  return (
    <span
      data-testid="custom-catchall-status"
      className={`rounded-full px-2.5 py-0.5 text-[10px] font-medium uppercase tracking-[0.14em] ${tone}`}
    >
      {label}
    </span>
  );
}

function describeStatus(status: CatchallToolStatus): {
  label: string;
  tone: string;
} {
  switch (status) {
    case "inProgress":
      return {
        label: "streaming",
        tone: "border border-[#FFAC4D33] bg-[#FFAC4D]/15 text-[#57575B]",
      };
    case "executing":
      return {
        label: "running",
        tone: "border border-[#BEC2FF] bg-[#BEC2FF1A] text-[#010507]",
      };
    case "complete":
      return {
        label: "done",
        tone: "border border-[#85ECCE4D] bg-[#85ECCE]/20 text-[#189370]",
      };
  }
}

function parseResult(result: string | undefined): unknown {
  if (result === undefined || result === null) return undefined;
  if (typeof result !== "string") return result;
  try {
    return JSON.parse(result);
  } catch {
    return result;
  }
}

function safeStringify(value: unknown): string {
  try {
    return JSON.stringify(value, null, 2);
  } catch {
    return String(value);
  }
}

"use client";

import React from "react";

// Rich per-tool renderer for the `search_flights` backend tool.
//
// Registered in page.tsx via `useRenderTool({ name: "search_flights", ... })`,
// this card shows the search origin/destination and a short list of
// flight results. It only renders once the backend returns; while the
// tool is still running it shows a compact loading state so the chat
// doesn't look frozen.

export interface Flight {
  airline?: string;
  flight?: string;
  depart?: string;
  arrive?: string;
  price_usd?: number;
}

export interface FlightListCardProps {
  loading: boolean;
  origin: string;
  destination: string;
  flights: Flight[];
}

export function FlightListCard({
  loading,
  origin,
  destination,
  flights,
}: FlightListCardProps) {
  return (
    <div
      data-testid="flight-list-card"
      className="my-3 rounded-2xl border border-[#DBDBE5] bg-white p-5 shadow-sm"
    >
      <div className="mb-4 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <span
            className="flex h-8 w-8 items-center justify-center rounded-full bg-[#BEC2FF1A] text-[#010507]"
            aria-hidden
          >
            ✈
          </span>
          <div className="font-semibold text-[#010507]">
            <span data-testid="flight-origin">{origin || "?"}</span>
            <span className="mx-1.5 text-[#838389]">→</span>
            <span data-testid="flight-destination">{destination || "?"}</span>
          </div>
        </div>
        {loading ? (
          <span className="text-[10px] uppercase tracking-[0.14em] text-[#57575B]">
            searching…
          </span>
        ) : (
          <span className="rounded-full border border-[#DBDBE5] bg-[#F7F7F9] px-2.5 py-0.5 text-[10px] font-medium uppercase tracking-[0.14em] text-[#57575B]">
            {flights.length} result{flights.length === 1 ? "" : "s"}
          </span>
        )}
      </div>

      {loading ? (
        <div className="space-y-2">
          <Skeleton />
          <Skeleton />
          <Skeleton />
        </div>
      ) : (
        <ul className="space-y-2">
          {flights.length === 0 ? (
            <li className="text-sm italic text-[#57575B]">
              No flights returned.
            </li>
          ) : (
            flights.map((f, i) => (
              <li
                key={`${f.flight ?? "flight"}-${i}`}
                data-testid="flight-row"
                className="flex items-center justify-between rounded-xl border border-[#E9E9EF] bg-[#FAFAFC] px-3 py-2.5 text-sm"
              >
                <div>
                  <div className="font-medium text-[#010507]">
                    {f.airline ?? "—"}{" "}
                    <span className="font-mono text-xs text-[#838389]">
                      {f.flight ?? ""}
                    </span>
                  </div>
                  <div className="text-xs text-[#57575B] mt-0.5">
                    {f.depart ?? "?"} → {f.arrive ?? "?"}
                  </div>
                </div>
                <div className="font-mono text-sm font-medium text-[#189370]">
                  {f.price_usd !== undefined ? `$${f.price_usd}` : "—"}
                </div>
              </li>
            ))
          )}
        </ul>
      )}
    </div>
  );
}

function Skeleton() {
  return (
    <div className="h-10 animate-pulse rounded-xl bg-[#F0F0F4]" aria-hidden />
  );
}

"use client";

import React from "react";

export interface WeatherCardProps {
  loading: boolean;
  location: string;
  temperature?: number;
  humidity?: number;
  windSpeed?: number;
  conditions?: string;
}

export function WeatherCard({
  loading,
  location,
  temperature,
  humidity,
  windSpeed,
  conditions,
}: WeatherCardProps) {
  return (
    <div
      data-testid="weather-card"
      className="rounded-2xl mt-4 mb-4 max-w-md w-full bg-[#EDEDF5] border border-[#DBDBE5] text-[#010507] shadow-sm"
    >
      <div className="p-5">
        <div className="flex items-start justify-between gap-4">
          <div>
            <div className="text-[10px] uppercase tracking-[0.14em] text-[#57575B] mb-1">
              Current weather
            </div>
            <h3
              data-testid="weather-city"
              className="text-xl font-semibold capitalize text-[#010507]"
            >
              {location || "Weather"}
            </h3>
            <p className="text-[#57575B] text-sm mt-0.5">
              {loading ? "Fetching weather..." : conditions || "—"}
            </p>
          </div>
          <div className="text-4xl leading-none" aria-hidden>
            {loading ? "..." : conditionsEmoji(conditions)}
          </div>
        </div>

        {!loading && (
          <>
            <div className="mt-5 text-4xl font-semibold text-[#010507] tracking-tight">
              {temperature ?? "--"}&deg;
              <span className="ml-1 text-lg font-normal text-[#57575B]">F</span>
            </div>
            <div className="mt-5 pt-4 border-t border-[#DBDBE5] grid grid-cols-2 gap-3 text-sm">
              <div data-testid="weather-humidity">
                <p className="text-[10px] uppercase tracking-[0.14em] text-[#57575B]">
                  Humidity
                </p>
                <p className="mt-1 font-medium text-[#010507]">
                  {humidity ?? "--"}%
                </p>
              </div>
              <div data-testid="weather-wind">
                <p className="text-[10px] uppercase tracking-[0.14em] text-[#57575B]">
                  Wind
                </p>
                <p className="mt-1 font-medium text-[#010507]">
                  {windSpeed ?? "--"} mph
                </p>
              </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

function conditionsEmoji(conditions?: string): string {
  if (!conditions) return "";
  const c = conditions.toLowerCase();
  if (c.includes("sun") || c.includes("clear")) return "sun";
  if (c.includes("rain") || c.includes("storm")) return "rain";
  if (c.includes("cloud")) return "cloud";
  if (c.includes("snow")) return "snow";
  return "";
}

