        // reference at examples/integrations/langgraph-python).
        // OpenGenerativeUI lives in /api/copilotkit-ogui for the same reason.
        // MCP Apps is in /api/copilotkit-mcp-apps.
      }),
    });

    const response = await handleRequest(req);
    console.log(`[copilotkit/route] Response status: ${response.status}`);
    return response;
  } catch (error: any) {
    console.error(`[copilotkit/route] ERROR: ${error.message}`);
    console.error(`[copilotkit/route] Stack: ${error.stack}`);
    return NextResponse.json(
      { error: error.message, stack: error.stack },
      { status: 500 },
    );
  }
};

export const GET = async () => {
  console.log("[copilotkit/route] GET /api/copilotkit (health probe)");

  let langGraphStatus = "unknown";
  try {
    const res = await fetch(`${LANGGRAPH_URL}/ok`, {
      signal: AbortSignal.timeout(3000),
    });
    langGraphStatus = res.ok ? "reachable" : `error (${res.status})`;
  } catch (e: any) {
    langGraphStatus = `unreachable (${e.message})`;
  }

  return NextResponse.json({
    status: "ok",
    langgraph_url: LANGGRAPH_URL,
    langgraph_status: langGraphStatus,
    env: {
      OPENAI_API_KEY: process.env.OPENAI_API_KEY ? "set" : "NOT SET",
      LANGSMITH_API_KEY: process.env.LANGSMITH_API_KEY ? "set" : "NOT SET",
      NODE_ENV: process.env.NODE_ENV,
    },
  });
};

"use client";

import React from "react";

/**
 * Step shape matches the `Step` TypedDict emitted by the Python deep agent's
 * custom `set_steps` tool (see `src/agents/gen_ui_agent.py`).
 * Status transitions: pending -> in_progress -> completed.
 */
export type Step = {
  id: string;
  title: string;
  status: "pending" | "in_progress" | "completed";
};

export function InlineAgentStateCard({
  steps,
  status,
}: {
  steps: Step[];
  status: "inProgress" | "complete";
}) {
  const total = steps.length;
  const done = steps.filter((s) => s.status === "completed").length;
  const headline =
    status === "complete" || (total > 0 && done === total)
      ? `All ${total} steps complete`
      : total > 0
        ? `Step ${Math.min(done + 1, total)} of ${total}`
        : "Planning…";

  return (
    <div
      data-testid="agent-state-card"
      className="my-3 mx-4 rounded-2xl border border-[#DBDBE5] bg-white p-4 shadow-sm"
    >
      <div className="flex items-center gap-2">
        {status === "inProgress" && done < total ? (
          <SpinnerIcon />
        ) : (
          <CheckIcon />
        )}
        <span className="text-sm font-semibold text-[#010507]">{headline}</span>
      </div>

      {steps.length > 0 && (
        <ol className="mt-3 space-y-2">
          {steps.map((step, idx) => (
            <li
              key={step.id ?? idx}
              data-testid="agent-step"
              data-status={step.status}
              className="flex items-start gap-3"
            >
              <StepMarker status={step.status} index={idx} />
              <span
                className={
                  "text-xs leading-5 " +
                  (step.status === "completed"
                    ? "text-[#838389] line-through"
                    : step.status === "in_progress"
                      ? "text-[#010507] font-medium"
                      : "text-[#57575B]")
                }
              >
                {step.title}
              </span>
            </li>
          ))}
        </ol>
      )}
    </div>
  );
}

function StepMarker({
  status,
  index,
}: {
  status: Step["status"];
  index: number;
}) {
  if (status === "completed") {
    return (
      <span className="mt-0.5 inline-flex h-5 w-5 flex-none items-center justify-center rounded-full bg-[#85ECCE] text-[#010507]">
        <svg
          className="h-3 w-3"
          fill="none"
          stroke="currentColor"
          viewBox="0 0 24 24"
        >
          <path
            strokeLinecap="round"
            strokeLinejoin="round"
            strokeWidth={3}
            d="M5 13l4 4L19 7"
          />
        </svg>
      </span>
    );
  }
  if (status === "in_progress") {
    return (
      <span className="mt-0.5 inline-flex h-5 w-5 flex-none items-center justify-center rounded-full bg-[#BEC2FF] text-[#010507]">
        <svg
          className="h-3 w-3 animate-spin"
          xmlns="http://www.w3.org/2000/svg"
          fill="none"
          viewBox="0 0 24 24"
        >
          <circle
            className="opacity-30"
            cx="12"
            cy="12"
            r="10"
            stroke="currentColor"
            strokeWidth="4"
          />
          <path
            className="opacity-90"
            fill="currentColor"
            d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"
          />
        </svg>
      </span>
    );
  }
  return (
    <span className="mt-0.5 inline-flex h-5 w-5 flex-none items-center justify-center rounded-full border border-[#DBDBE5] bg-white text-[10px] font-semibold text-[#838389]">
      {index + 1}
    </span>
  );
}

function SpinnerIcon() {
  return (
    <svg
      className="w-4 h-4 animate-spin text-[#010507]"
      xmlns="http://www.w3.org/2000/svg"
      fill="none"
      viewBox="0 0 24 24"
    >
      <circle
        className="opacity-25"
        cx="12"
        cy="12"
        r="10"
        stroke="currentColor"
        strokeWidth="4"
      />
      <path
        className="opacity-75"
        fill="currentColor"
        d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
      />
    </svg>
  );
}

function CheckIcon() {
  return (
    <svg
      className="w-4 h-4 text-[#189370]"
      fill="none"
      stroke="currentColor"
      viewBox="0 0 24 24"
    >
      <path
        strokeLinecap="round"
        strokeLinejoin="round"
        strokeWidth={3}
        d="M5 13l4 4L19 7"
      />
    </svg>
  );
}

