                const pct = total > 0 ? ((val / total) * 100).toFixed(0) : "0";
                return (
                  <div
                    key={index}
                    style={{
                      display: "flex",
                      alignItems: "center",
                      gap: 12,
                      fontSize: "0.85rem",
                    }}
                  >
                    <span
                      style={{
                        display: "inline-block",
                        width: 12,
                        height: 12,
                        borderRadius: 999,
                        flexShrink: 0,
                        backgroundColor:
                          CHART_COLORS[index % CHART_COLORS.length],
                      }}
                    />
                    <span
                      style={{
                        flex: 1,
                        color: "#010507",
                        overflow: "hidden",
                        textOverflow: "ellipsis",
                        whiteSpace: "nowrap",
                      }}
                    >
                      {item.label}
                    </span>
                    <span
                      style={{
                        color: "#57575B",
                        fontVariantNumeric: "tabular-nums",
                      }}
                    >
                      {val.toLocaleString()}
                    </span>
                    <span
                      style={{
                        color: "#57575B",
                        width: 40,
                        textAlign: "right",
                        fontVariantNumeric: "tabular-nums",
                      }}
                    >
                      {pct}%
                    </span>
                  </div>
                );
              })}
            </div>
          </>
        )}
      </div>
    );
  },

  BarChart: ({ props }) => {
    const { isNew } = useSeenIndices();
    const data = props.data ?? [];
    const safeData = Array.isArray(data) ? data : [];

    return (
      <div
        style={{
          border: "1px solid #DBDBE5",
          borderRadius: 16,
          padding: 20,
          background: "white",
          boxShadow: "0 1px 3px rgba(1, 5, 7, 0.04)",
          maxWidth: 640,
          margin: "0 auto",
          display: "flex",
          flexDirection: "column",
          gap: 12,
          overflow: "hidden",
        }}
      >
        {/* Scoped keyframe — no globals.css needed */}
        <style>{`
          @keyframes barSlideIn {
            from { transform: translateY(40px); opacity: 0; }
            20% { opacity: 1; }
            to { transform: translateY(0); opacity: 1; }
          }
        `}</style>

        <div style={{ display: "flex", flexDirection: "column", gap: 2 }}>
          <div style={{ fontWeight: 600, fontSize: "1rem", color: "#010507" }}>
            {props.title}
          </div>
          <div style={{ color: "#57575B", fontSize: "0.85rem" }}>
            {props.description}
          </div>
        </div>

        {safeData.length === 0 ? (
          <div
            style={{
              color: "#838389",
              textAlign: "center",
              padding: "32px 0",
              fontSize: "0.85rem",
            }}
          >
            No data available
          </div>
        ) : (
          <ResponsiveContainer width="100%" height={280}>
            <RechartsBarChart
              data={safeData}
              margin={{ top: 12, right: 12, bottom: 4, left: -8 }}
            >
              <CartesianGrid
                strokeDasharray="3 3"
                stroke="#E9E9EF"
                vertical={false}
              />
              <XAxis
                dataKey="label"
                tick={{ fontSize: 12, fill: "#57575B" }}
                stroke="#E9E9EF"
                tickLine={false}
                axisLine={false}
              />
              <YAxis
                tick={{ fontSize: 12, fill: "#57575B" }}
                stroke="#E9E9EF"
                tickLine={false}
                axisLine={false}
              />
              <Tooltip
                contentStyle={CHART_TOOLTIP_STYLE}
                cursor={{ fill: "#F4F4F7", opacity: 0.5 }}
              />
              <Bar
                isAnimationActive={false}
                dataKey="value"
                radius={[6, 6, 0, 0]}
                maxBarSize={48}
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                shape={
                  ((barProps: any) => (
                    <AnimatedBar
                      {...barProps}
                      isNew={isNew(barProps.index as number)}
                    />
                    // eslint-disable-next-line @typescript-eslint/no-explicit-any
                  )) as any
                }
              >
                {safeData.map((_, index) => (
                  <Cell
                    key={index}
                    fill={CHART_COLORS[index % CHART_COLORS.length]}
                  />
                ))}
              </Bar>
            </RechartsBarChart>
          </ResponsiveContainer>
        )}
      </div>
    );
  },
};

