                <option key={tz} value={tz}>
                  {tz}
                </option>
              ))}
            </select>
          </label>

          <div>
            <span className="text-sm font-medium text-gray-700">
              Recent Activity
            </span>
            <div className="mt-2 flex flex-col gap-2">
