          Reasoning
        </span>
        <span className="text-[#57575B]">
          {isStreaming ? "Thinking…" : hasContent ? "Agent reasoning" : "…"}
        </span>
      </div>
      {hasContent && (
        <div className="mt-1.5 whitespace-pre-wrap italic text-[#57575B]">
          {message.content}
        </div>
      )}
    </div>
  );
}

